    // b is already a u8, no conversion needed
}

// ✅ SAFE - Use as_bytes()
let bytes: &[u8] = s.as_bytes();  // Preserves UTF-8
```

#### 2. Use Safe Conversion Methods

```rust
// ✅ SAFE - Encode UTF-8
let mut buf = [0u8; 4];
let bytes = ch.encode_utf8(&mut buf).as_bytes();

// ✅ SAFE - Use String methods
